+    // BatchNorm params (16 channels)
+    this.bnGamma = new Float32Array(16).fill(1.0);
+    this.bnBeta = new Float32Array(16).fill(0.0);
+    this.bnMean = new Float32Array(16).fill(0.0);
+    this.bnVar = new Float32Array(16).fill(1.0);
