+    // Projection: 16 → embeddingDim (used when RuVector not available)
+    this.projWeights = new Float32Array(16 * this.embeddingDim);
+    for (let i = 0; i < this.projWeights.length; i++) {
+      this.projWeights[i] = randRange(-0.1, 0.1);
+    }
